        book_id = str(uuid.uuid4())
        db.collection(Collections.PRODUCTS).document(book_id).set({
            "product_id":  book_id,
            "category_id": category_ids[book["category"]],
            "name":        book["name"],
            "author":      book["author"],
            "description": book["description"],
            "price":       book["price"],
            "stock":       book["stock"],
            "image":       "",
            "created_at":  now,
        })
        print(f"  ✔ Book: {book['name']} by {book['author']}")

